package com.library; import com.library.entity.Book; import com.library.repository.BookRepository; import jakarta.persistence.EntityManager; import jakarta.persistence.PersistenceContext; import org.springframework.boot.CommandLineRunner; import org.springframework.boot.SpringApplication; import org.springframework.boot.autoconfigure.SpringBootApplication; import org.springframework.context.annotation.Bean; import org.springframework.transaction.PlatformTransactionManager; import org.springframework.transaction.TransactionStatus; import org.springframework.transaction.support.DefaultTransactionDefinition; @SpringBootApplication public class LibraryApplication { @PersistenceContext private EntityManager entityManager; private final PlatformTransactionManager transactionManager; public LibraryApplication(PlatformTransactionManager transactionManager) { this.transactionManager = transactionManager; } public static void main(String[] args) { SpringApplication.run(LibraryApplication.class, args); } @Bean public CommandLineRunner runComparison(BookRepository springDataRepository) { return (args) -> { System.out.println("\n--- APPROACH 1: STANDARD HIBERNATE / JPA ENGINE ---"); TransactionStatus status = transactionManager.getTransaction(new DefaultTransactionDefinition()); try { Book hibernateBook = new Book("Hibernate Native Guide", "Gavin King"); entityManager.persist(hibernateBook); transactionManager.commit(status); System.out.println("Saved successfully using explicit EntityManager: " + hibernateBook); } catch (Exception e) { transactionManager.rollback(status); throw e; } System.out.println("\n--- APPROACH 2: SPRING DATA JPA ABSTRACTION ---"); Book springBook = new Book("Spring Data Mastery", "Oliver Gierke"); Book savedSpringBook = springDataRepository.save(springBook); System.out.println("Saved successfully using Repository Abstraction: " + savedSpringBook); System.out.println("\n=======================================================\n"); }; } }
